function adaptInvalid(options) {
    if (options.x & 1) {
        options.x -= 1;
        options.width += 1;
    }
    if (options.width & 1) {
        options.width += 1;
    }
}

function adaptInvalid(options) {
    options.x = 0;
    options.y = 0;
    options.width = 320;
    options.height = 240;
}

